class Solution {
public:
    string concatHex36(int n) {
        int n2 = n * n;
        int n3 = n * n * n;
        string hex = "";
        while (n2 > 0) {
            int remainder = n2 % 16;
            if (remainder < 10) {
                hex = to_string(remainder) + hex;
            } else {
                hex = char('A' + remainder - 10) + hex;
            }
            n2 /= 16;
        }
        string base36 = "";
        while (n3 > 0) {
            int remainder = n3 % 36;
            if (remainder < 10) {
                base36 = to_string(remainder) + base36;
            } else {
                base36 = char('A' + remainder - 10) + base36;
            }
            n3 /= 36;
        }
        return hex + base36;
    }
};

